// Name: Parse + Normalize (Subject/Recipients/Meta) + Sender Role
// Mode: Run Once for All Items

// --- CONFIG ---
const INTERNAL_DOMAINS = ['scalevirtually.com'];
const INTERNAL_ADDRESSES = [
  'placements@scalevirtually.com',
  'placements.sv@scalevirtually.com',
  'pdev@scalevirtually.com',
  'coach@scalevirtually.com',
  'placements@scalevirtually.com',
].map(a => a.toLowerCase());

// --- Helpers ---
const getHeader = (obj, key) => {
  if (!obj) return '';
  const k = Object.keys(obj).find(h => h.toLowerCase() === key.toLowerCase());
  return k ? obj[k] : '';
};

const isInternalEmail = (addr='') => {
  const a = String(addr).toLowerCase().trim();
  if (!a) return false;
  if (INTERNAL_ADDRESSES.includes(a)) return true;
  const dom = a.split('@')[1] || '';
  return INTERNAL_DOMAINS.some(d => dom.endsWith(d));
};

const extractEmails = (value) => {
  // Accept comma-separated strings or arrays; return array of bare emails (lowercased)
  const texts = Array.isArray(value) ? value : [value];
  const out = [];
  for (const t of texts) {
    if (!t) continue;
    const matches = String(t).match(/[\w.+-]+@[\w.-]+\.[A-Za-z]{2,}/g) || [];
    for (const m of matches) out.push(m.toLowerCase());
  }
  return [...new Set(out)];
};

const firstExternal = (emails) => {
  for (const e of emails) if (!isInternalEmail(e)) return e;
  return '';
};

const normalizeSubject = (subj) => {
  let s = String(subj || '');
  s = s.replace(/^\s*(re|fwd|fw)\s*:\s*/i, '');
  return s.trim();
};

const parseCompanyFromSubject = (subj) => {
  const s = normalizeSubject(subj);
  const rx = /scale\s+virtually\s*:\s*va\s*candidates\s*for\s+(.+)$/i;
  const m = s.match(rx);
  if (m && m[1]) return m[1].trim().replace(/^["'\s]+|["'\s]+$/g, '');
  return '';
};

const toISO = (msOrStr) => {
  if (!msOrStr) return '';
  if (/^\d+$/.test(String(msOrStr))) {
    const n = Number(msOrStr);
    if (!Number.isNaN(n)) return new Date(n).toISOString();
  }
  const d = new Date(msOrStr);
  return isNaN(d.getTime()) ? '' : d.toISOString();
};

const boolFlag = (v) => Boolean(v);

// --- Main ---
const out = [];

for (const item of $input.all()) {
  const j = item.json || {};
  const headers = j.headers || {};

  // Subject / company
  const subjectRaw =
    j.Subject || j.subject || getHeader(headers, 'subject') || '';
  const subjectNorm = normalizeSubject(subjectRaw);
  const company = parseCompanyFromSubject(subjectRaw);

  // Participants (handle CC in any casing)
  const toList = extractEmails(
    j.To ?? j.to ?? getHeader(headers, 'to') ?? []
  );
  const ccList = extractEmails(
    j.CC ?? j.Cc ?? j.cc ?? getHeader(headers, 'cc') ?? getHeader(headers, 'CC') ?? []
  );

  const fromRaw = j.From ?? j.from ?? getHeader(headers, 'from') ?? '';
  const fromEmail = extractEmails(fromRaw)[0] || '';

  // Reply-To priority for primary client
  const replyToList = extractEmails(getHeader(headers, 'reply-to') || []);
  const externals = [...new Set([...toList, ...ccList].filter(e => !isInternalEmail(e)))];

  const primaryClientEmail =
    firstExternal(replyToList) ||
    firstExternal(toList) ||
    firstExternal(ccList) ||
    (!isInternalEmail(fromEmail) ? fromEmail : '') ||
    '';

  // Meta / IDs
  const threadId = j.threadId || j.thread_id || '';
  const gmailMessageId =
    j.id ||
    j.messageId ||
    j['Message-Id'] ||
    getHeader(headers, 'Message-Id') ||
    getHeader(headers, 'message-id') ||
    '';
  const rfcMessageId =
    getHeader(headers, 'Message-Id') ||
    getHeader(headers, 'message-id') ||
    '';
  const inReplyTo = getHeader(headers, 'In-Reply-To') || getHeader(headers, 'in-reply-to') || '';
  const references = getHeader(headers, 'References') || getHeader(headers, 'references') || '';

  const sentAtISO = toISO(j.internalDate || j.Date || getHeader(headers, 'date'));
  const sentAtEpoch = sentAtISO ? new Date(sentAtISO).getTime() : 0;

  // Flags
  const autoSubmitted = (getHeader(headers, 'Auto-Submitted') || '').toLowerCase();
  const precedence = (getHeader(headers, 'Precedence') || '').toLowerCase();
  const xAutoreply = (getHeader(headers, 'X-Autoreply') || '').toLowerCase();
  const maybeAutoReply =
    autoSubmitted.includes('auto') ||
    xAutoreply.includes('auto') ||
    precedence === 'bulk' || precedence === 'list' ||
    /out of office|automatic reply/i.test(subjectRaw);

  const maybeBounce =
    /mailer-daemon@|postmaster@/i.test(fromEmail) ||
    /undeliverable|delivery status notification|address not found/i.test(subjectRaw);

  // Participants snapshots
  const participantsAll = [...new Set([fromEmail, ...toList, ...ccList].filter(Boolean))];
  const participantsExternal = participantsAll.filter(e => !isInternalEmail(e));
  const participantsInternal = participantsAll.filter(e => isInternalEmail(e));

  // 👉 NEW: latest message role/direction
  const latest_message_from_email = fromEmail || '';
  const latest_message_role = isInternalEmail(latest_message_from_email) ? 'internal' : 'client';
  const latest_message_direction = latest_message_role === 'internal' ? 'outbound' : 'inbound';

  out.push({
    json: {
      // Parsed
      company,
      subject_normalized: subjectNorm,
      primary_client_email: primaryClientEmail,
      external_recipients: externals,     // array (non-internal recipients in To/Cc)
      to_list: toList,                    // array
      cc_list: ccList,                    // array
      participants_external: participantsExternal,
      participants_internal: participantsInternal,

      // IDs / Meta
      thread_id: threadId,
      message_id: gmailMessageId,
      gmail_message_id: gmailMessageId,
      rfc_message_id: rfcMessageId || '',
      in_reply_to: inReplyTo,
      references: references,
      sent_at: sentAtISO,
      sent_at_epoch: sentAtEpoch,

      // Originals / audit
      subject_raw: subjectRaw,
      from: fromRaw,

      // Heuristics
      maybe_auto_reply: boolFlag(maybeAutoReply),
      maybe_bounce: boolFlag(maybeBounce),

      // 👉 NEW: role/direction of the latest message
      latest_message_from_email,
      latest_message_role,          // 'internal' | 'client'
      latest_message_direction,     // 'outbound' | 'inbound'

      // Versioning
      schema_version: 'p+n.v2',
    }
  });
}

return out;

// Name: Dedupe (Static Data) — Gmail messageId + threadId
// Mode: Run Once for All Items

const SD = $getWorkflowStaticData('global');  // <- correct helper for Code node
const TTL_MS   = 7 * 24 * 60 * 60 * 1000; // 7 days
const MAX_KEYS = 500;

if (!SD.processedMsg) SD.processedMsg = {};
const now = Date.now();

// GC old entries
for (const [k, ts] of Object.entries(SD.processedMsg)) {
  if (!ts || (now - ts) > TTL_MS) delete SD.processedMsg[k];
}

const out = [];
for (const item of $input.all()) {
  const j = item.json || {};
  const msgId =
    j.id ||
    j.messageId ||
    j["Message-Id"] ||
    j.headers?.["Message-Id"] ||
    j.headers?.["message-id"];

  const threadId = j.threadId || j.thread_id || '';

  if (!msgId) { out.push(item); continue; } // don’t block if missing
  const key = `${msgId}::${threadId}`;

  if (SD.processedMsg[key]) {
    // seen before → drop
    continue;
  }

  SD.processedMsg[key] = now; // mark seen
  out.push(item);
}

// Size cap eviction (oldest first)
const keys = Object.keys(SD.processedMsg);
if (keys.length > MAX_KEYS) {
  keys.sort((a, b) => SD.processedMsg[a] - SD.processedMsg[b]);
  for (let i = 0; i < keys.length - MAX_KEYS; i++) delete SD.processedMsg[keys[i]];
}

return out;

// Name: Prepare Thread for AI
// Mode: Run Once for All Items

// ===== CONFIG =====
const INTERNAL_DOMAINS = ['scalevirtually.com'];
const INTERNAL_ADDRESSES = [
  'placements@scalevirtually.com',
  'placements.sv@scalevirtually.com',
  'pdev@scalevirtually.com',
  'coach@scalevirtually.com',
  'placements@scalevirtually.com',
];
// Char budgets
const MAX_EXCERPT_CHARS = 1200;
const MAX_TURN_CHARS = 600;     // per message, after cleanup
const MAX_QUOTED_TAIL = 2000;   // cap leftover quoted text if any leaks
const SCHEMA_VERSION = 'prep.v1';

// ===== Helpers =====
const getHeaderVal = (headers, name) => {
  if (!headers) return '';
  if (Array.isArray(headers)) {
    const h = headers.find(h => (h.name || '').toLowerCase() === name.toLowerCase());
    return h ? h.value || '' : '';
  }
  const key = Object.keys(headers).find(k => k.toLowerCase() === name.toLowerCase());
  return key ? headers[key] : '';
};

const extractEmails = (value) => {
  const texts = Array.isArray(value) ? value : [value];
  const out = [];
  for (const t of texts) {
    if (!t) continue;
    const matches = String(t).match(/[\w.+-]+@[\w.-]+\.[A-Za-z]{2,}/g) || [];
    for (const m of matches) out.push(m.toLowerCase());
  }
  return [...new Set(out)];
};

const isInternalEmail = (addr) => {
  const a = (addr || '').toLowerCase().trim();
  if (!a) return false;
  if (INTERNAL_ADDRESSES.includes(a)) return true;
  const dom = a.split('@')[1] || '';
  return INTERNAL_DOMAINS.some(d => dom.endsWith(d));
};

const base64UrlDecode = (input) => {
  if (!input) return '';
  let s = String(input).replace(/-/g, '+').replace(/_/g, '/');
  while (s.length % 4) s += '=';
  try { return Buffer.from(s, 'base64').toString('utf8'); } catch { return ''; }
};

const decodeQuotedPrintable = (str) => {
  if (!str) return '';
  let s = str.replace(/=\r?\n/g, '');
  s = s.replace(/=([A-Fa-f0-9]{2})/g, (_, hex) => {
    try { return String.fromCharCode(parseInt(hex, 16)); } catch { return _; }
  });
  return s;
};

const htmlToText = (html) => {
  if (!html) return '';
  let s = String(html)
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<\/(p|div|br|li|tr|h[1-6])>/gi, '\n')
    .replace(/<(ul|ol|table|thead|tbody|tfoot|tr)>/gi, '\n')
    .replace(/<[^>]+>/g, '')
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/gi, "'")
    .replace(/&lt;/gi, '<')
    .replace(/&gt;/gi, '>');
  s = s.replace(/\r/g, '').replace(/\t/g, '  ');
  s = s.split('\n').map(l => l.replace(/\s+$/,'')).join('\n');
  s = s.replace(/\n{3,}/g, '\n\n').trim();
  return s;
};

const stripQuotedAndSignature = (text) => {
  if (!text) return '';
  let s = text;
  s = s.replace(/(^|\n)On .*wrote:\n[\s\S]*$/i, '$1');
  s = s.replace(/(^|\n)From: .*?\nSent: .*?\nTo: [\s\S]*$/i, '$1');
  s = s.split('\n').filter(l => !/^\s*>/.test(l)).join('\n');
  s = s.replace(/(^|\n)--\s*\n[\s\S]*$/g, '$1');
  s = s.replace(/(^|\n)Regards?,?[\s\S]{0,200}$/i, '$1');
  s = s.replace(/(^|\n)Best(?: regards)?,?[\s\S]{0,200}$/i, '$1');
  if (s.length > MAX_EXCERPT_CHARS + MAX_QUOTED_TAIL) {
    s = s.slice(0, MAX_EXCERPT_CHARS + MAX_QUOTED_TAIL);
  }
  return s.trim();
};

const extractBodyText = (payload) => {
  if (!payload) return '';
  const mime = (payload.mimeType || '').toLowerCase();
  const data = payload.body && payload.body.data ? payload.body.data : null;

  let current = '';
  if (data && (mime.includes('text/plain') || mime === 'text/html')) {
    const decoded = base64UrlDecode(data);
    current = mime.includes('html') ? htmlToText(decoded) : decoded;
  }
  let bestChild = '';
  const parts = payload.parts || [];
  for (const p of parts) {
    const child = extractBodyText(p);
    if (child && child.length > bestChild.length) bestChild = child;
  }
  const chosen = (bestChild.length > current.length) ? bestChild : current;
  const maybeQP = /=\r?\n|=[A-Fa-f0-9]{2}/.test(chosen);
  const cleaned = maybeQP ? decodeQuotedPrintable(chosen) : chosen;
  return cleaned;
};

const clip = (s, n) => (s && s.length > n ? s.slice(0, n).trim() : s || '');

const parseNameEmail = (fromHeader) => {
  const email = extractEmails(fromHeader)[0] || '';
  if (!fromHeader) return { name: '', email };
  const m = String(fromHeader).match(/^\s*("?)([^"<]+?)\1\s*<[^>]+>\s*$/);
  if (m && m[2]) return { name: m[2].trim(), email };
  const name = String(fromHeader).replace(email, '').replace(/[<>"]/g,'').trim();
  return { name, email };
};

const hasZoomLink = (t) => /(zoom\.us\/j|zoom\.us\/my|teams\.microsoft\.com|meet\.google\.com)\//i.test(t || '');
const hasAnyLink = (t) => /https?:\/\/\S+/i.test(t || '');
// Broadened schedule and approval detectors
const containsScheduley = (t) =>
  /\b(schedule|reschedul|calendar|call|meeting|interview|availability|slot|time|start date|start on|working schedule|shift|8[:.]?00\s*(am|pm)?|9[:.]?00\s*(am|pm)?|11[:.]?00\s*(am|pm)?)\b/i.test(t || '');
const containsApproval = (t) =>
  /\b(approved|proceed|go ahead|let'?s move|green[-\s]?light|move forward|offer|hire|welcome aboard|invite(d)?\s+.*\s+to\s+(our|the)\s+team)\b/i.test(t || '');

// ===== Build =====
const items = $input.all();

// --- Pull canonical fields from "Parse + Normalize" (Option B) ---
let pnn = {};
try { pnn = ($items('Parse + Normalize')[0] || {}).json || {}; } catch { /* ignore if node not present */ }

let company = pnn.company || '';
let subject = pnn.subject_normalized || pnn.subject_raw || 'VA Candidates';
let participantsExternal = Array.isArray(pnn.participants_external) ? pnn.participants_external : [];
let participantsInternal = Array.isArray(pnn.participants_internal) ? pnn.participants_internal : [];
let maybeAutoReplyUpstream = !!pnn.maybe_auto_reply;
let maybeBounceUpstream = !!pnn.maybe_bounce;

// Determine thread messages input shape (do NOT overwrite p+n fields if they exist)
let threadId = '';
let messages = [];
if (items.length === 1 && Array.isArray(items[0].json.messages)) {
  const j = items[0].json;
  messages = j.messages || [];
  threadId = j.threadId || j.thread_id || (messages[0]?.threadId || '');
  if (!participantsExternal.length && Array.isArray(j.participants_external)) participantsExternal = j.participants_external;
  if (!participantsInternal.length && Array.isArray(j.participants_internal)) participantsInternal = j.participants_internal;
  if (!subject && (j.subject || j.subject_normalized)) subject = j.subject || j.subject_normalized;
  if (!company && j.company) company = j.company;
} else {
  messages = items.map(i => i.json);
  const first = items[0]?.json || {};
  threadId = first.threadId || first.thread_id || '';
  if (!subject && (first.subject || first.subject_normalized)) subject = first.subject || first.subject_normalized;
  if (!company && first.company) company = first.company;
  if (!participantsExternal.length && Array.isArray(first.participants_external)) participantsExternal = first.participants_external;
  if (!participantsInternal.length && Array.isArray(first.participants_internal)) participantsInternal = first.participants_internal;
}

// Sort by time (ascending)
messages.sort((a, b) => {
  const ta = Number(a.internalDate || 0);
  const tb = Number(b.internalDate || 0);
  return ta - tb;
});

// Build transcript
const transcript = [];
for (const m of messages) {
  const headers = m.payload?.headers || m.headers || {};
  const fromHdr = getHeaderVal(headers, 'From') || m.From || '';
  const { name: from_name, email: from_email } = parseNameEmail(fromHdr);

  const text = extractBodyText(m.payload) || m.snippet || '';
  const clean = stripQuotedAndSignature(htmlToText(text));
  const normalized = clean.replace(/\r/g, '').replace(/\n{3,}/g, '\n\n').trim();

  const body = clip(normalized, MAX_TURN_CHARS);

  const role = isInternalEmail(from_email) ? 'internal' : 'client';
  const whenISO = (() => {
    const ts = Number(m.internalDate || 0);
    if (ts) return new Date(ts).toISOString();
    const d = getHeaderVal(headers, 'Date');
    return d ? new Date(d).toISOString() : '';
  })();

  const gmail_message_id = m.id || '';
  const rfc_message_id = getHeaderVal(headers, 'Message-ID') || '';

  transcript.push({
    i: transcript.length,
    gmail_message_id,
    rfc_message_id,
    date_iso: whenISO,
    epoch: whenISO ? new Date(whenISO).getTime() : 0,
    from_email,
    from_name,
    role,
    text: body,
    has_links: hasAnyLink(body),
    has_zoom_link: hasZoomLink(body),
    word_count: body ? body.split(/\s+/).filter(Boolean).length : 0,
  });
}

// Pointers & summary flags
let last_client_index = -1;
let last_internal_index = -1;
for (let i = transcript.length - 1; i >= 0; i--) {
  if (last_client_index === -1 && transcript[i].role === 'client') last_client_index = i;
  if (last_internal_index === -1 && transcript[i].role === 'internal') last_internal_index = i;
  if (last_client_index !== -1 && last_internal_index !== -1) break;
}

const latestClientText = last_client_index >= 0 ? transcript[last_client_index].text : '';
const summary_flags = {
  contains_schedule: containsScheduley(latestClientText),
  contains_offer_or_approval: containsApproval(latestClientText),
  maybe_auto_reply: Boolean(maybeAutoReplyUpstream) || /out of office|automatic reply/i.test(latestClientText),
  maybe_bounce: Boolean(maybeBounceUpstream),
};

// --- NEW: Enrich participants with addresses seen in the transcript ---
const allSeen = [...new Set(transcript.map(t => t.from_email).filter(Boolean))];
const externalsSeen = allSeen.filter(e => !isInternalEmail(e));
const internalsSeen = allSeen.filter(e => isInternalEmail(e));
participantsExternal = [...new Set([...(participantsExternal || []), ...externalsSeen])];
participantsInternal = [...new Set([...(participantsInternal || []), ...internalsSeen])];

// Thread title fallback
const thread_title = subject || (company ? `VA Candidates for ${company}` : 'VA Candidates');

// Output
return [
  {
    json: {
      thread_id: threadId,
      subject: subject || thread_title,
      company,
      participants_internal: participantsInternal,
      participants_external: participantsExternal,
      transcript,
      last_client_index,
      last_internal_index,
      summary_flags,
      schema_version: SCHEMA_VERSION,
    }
  }
];

