// Name: Parse + Guardrails
// Mode: Run Once for All Items

// ---------- CONFIG ----------
const NODE_PREPARE = 'Prepare Thread for AI';
const NODE_AGENT   = 'AI Agent: Thread Classifier';

// Confidence thresholds
const CONF_AUTOSEND_MIN = 0.80;  // min to auto-send a follow-up
const CONF_HUMAN_MIN    = 0.60;  // below this -> Uncertain/HUMAN_REVIEW

// Cooldown before a follow-up (ms)
const MIN_COOLDOWN_MS = 24 * 60 * 60 * 1000; // 24h

// Quiet hours block (optional). Set to null to disable.
const QUIET_HOURS = null; // e.g., { startHour: 21, endHour: 8, tz: 'America/New_York' }

// Unsubscribe/stop phrases (latest external only)
const UNSUB_RX = /\b(unsubscribe|remove me|stop emailing|stop message|do not contact|don't contact)\b/i;

// Allowed labels
const ALLOWED = ["Approved","Rejected","MoreOptions","Scheduling","Question","NoReply","Noise","Uncertain"];

// ---------- HELPERS ----------
const stripFences = (s='') =>
  String(s).trim()
    .replace(/^```(?:json)?\s*/i,'')
    .replace(/```$/,'');

const safeJson = (s) => { try { return JSON.parse(s); } catch { return {}; } };

const clamp01 = (n) => Math.max(0, Math.min(1, Number(n)));

const nowMs = () => Date.now();

const inQuietHours = (cfg) => {
  if (!cfg) return false;
  const { startHour, endHour, tz } = cfg;
  const now = new Date();
  // Basic local-hour check; if you need strict TZ, precompute in an upstream node.
  const hr = now.getHours();
  if (startHour <= endHour) return hr >= startHour && hr < endHour;
  // Wraps midnight
  return (hr >= startHour) || (hr < endHour);
};

// ---------- INPUTS ----------
const prep = ($items(NODE_PREPARE)[0] || {}).json || {};
const agentRaw = ($items(NODE_AGENT)[0] || {}).json || {};
let agentOut = agentRaw;

// If the agent returned { output: "```json ... ```" }, parse it
if (typeof agentRaw.output === 'string') {
  const str = stripFences(agentRaw.output);
  agentOut = safeJson(str);
}

// Normalize + validate
let label = ALLOWED.includes(agentOut.label) ? agentOut.label : 'Uncertain';
let confidence = clamp01(agentOut.confidence ?? 0.5);
let evidence = String(agentOut.evidence || '').slice(0, 200);
let next_actions = Array.isArray(agentOut.next_actions)
  ? agentOut.next_actions.slice(0,5).map(x => String(x).trim()).filter(Boolean)
  : [];

// ---------- DERIVED CONTEXT ----------
const summary = prep.summary_flags || {};
const transcript = Array.isArray(prep.transcript) ? prep.transcript : [];
const lastClientIdx   = Number.isInteger(prep.last_client_index) ? prep.last_client_index : -1;
const lastInternalIdx = Number.isInteger(prep.last_internal_index) ? prep.last_internal_index : -1;

const latestExternalText = lastClientIdx >= 0 ? (transcript[lastClientIdx]?.text || '') : '';
const lastInternalTs = lastInternalIdx >= 0 ? (transcript[lastInternalIdx]?.epoch || 0) : 0;

// Has external since our last outbound?
const hasExternalSinceLastOutbound = lastClientIdx > lastInternalIdx;

// Unsubscribe detector (latest external only)
const hasUnsubscribe = UNSUB_RX.test(latestExternalText);

// Summary-based hard-stops
const isNoise = !!(summary.maybe_auto_reply || summary.maybe_bounce);

// ---------- GUARDRAIL ADJUSTMENTS ----------
if (isNoise) {
  label = 'Noise';
  confidence = Math.max(confidence, 0.9); // deterministic override
  evidence = evidence || 'Auto-reply/bounce detected.';
}

if (!ALLOWED.includes(label)) label = 'Uncertain';

// ---------- DECISION ENGINE ----------
let action = 'STOP';
let reason = 'Default stop.';

// Consider quiet hours
const quietNow = inQuietHours(QUIET_HOURS);

// Autosend follow-up is ONLY allowed for NoReply with strict preconditions
if (label === 'NoReply') {
  // Must be confident
  const confOK = confidence >= CONF_AUTOSEND_MIN;
  // No external after our last outbound
  const noNewExternal = !hasExternalSinceLastOutbound;
  // Respect cooldown
  const cooldownOK = (nowMs() - lastInternalTs) >= MIN_COOLDOWN_MS;
  // No unsubscribe/stop request
  const safeToContact = !hasUnsubscribe;
  // Not noise, not quiet hours
  const safeContext = !isNoise && !quietNow;

  if (confOK && noNewExternal && cooldownOK && safeToContact && safeContext) {
    action = 'AUTOSEND_FOLLOWUP';
    reason = 'NoReply with high confidence, cooldown met, safe to contact.';
  } else {
    action = 'HUMAN_REVIEW';
    reason = [
      confOK ? null : 'Low confidence',
      noNewExternal ? null : 'Client replied after last outbound',
      cooldownOK ? null : 'Cooldown not met',
      safeToContact ? null : 'Unsubscribe/stop detected',
      safeContext ? null : 'Quiet hours'
    ].filter(Boolean).join('; ');
  }
}
// Never auto-send for these labels; we just update state and stop.
else if (['Approved','Rejected','Scheduling','MoreOptions','Question','Noise'].includes(label)) {
  action = 'STOP';
  reason = `Terminal or handled label: ${label}.`;
}
// Fallbacks & uncertainty
else {
  action = 'HUMAN_REVIEW';
  reason = 'Uncertain or unmatched label.';
}

// Compute a recommended earliest send time (for Wait-until) if we’re in cooldown or quiet hours
let send_after_epoch = 0;
if (action === 'AUTOSEND_FOLLOWUP') {
  send_after_epoch = nowMs(); // ready now
} else if (label === 'NoReply') {
  const needCooldownMs = Math.max(0, MIN_COOLDOWN_MS - (nowMs() - lastInternalTs));
  let unblockAt = nowMs() + needCooldownMs;
  // If quiet hours, push to endHour today/tomorrow (minimal; for strict TZ do upstream)
  if (quietNow && QUIET_HOURS) {
    const d = new Date();
    const target = new Date(d);
    const { endHour } = QUIET_HOURS;
    target.setHours(endHour, 0, 0, 0);
    if (target.getTime() <= d.getTime()) target.setDate(target.getDate() + 1);
    unblockAt = Math.max(unblockAt, target.getTime());
  }
  send_after_epoch = unblockAt || 0;
}

// ---------- OUTPUT ----------
return [
  {
    json: {
      ...prep,  // ✅ keep everything from Prepare Thread for AI (participants, transcript, etc.)

      // normalized classifier
      label,
      confidence,
      evidence,
      next_actions,

      // guardrails context
      safeguards: {
        is_noise: isNoise,
        has_unsubscribe: hasUnsubscribe,
        has_external_since_last_outbound: hasExternalSinceLastOutbound,
        cooldown_met: (nowMs() - lastInternalTs) >= MIN_COOLDOWN_MS,
        quiet_hours: quietNow,
        min_cooldown_ms: MIN_COOLDOWN_MS,
        conf_autosend_min: CONF_AUTOSEND_MIN
      },

      // final decision
      action,                 // "AUTOSEND_FOLLOWUP" | "HUMAN_REVIEW" | "STOP"
      reason,
      send_after_epoch,       // for Wait-until; 0 means "now" or not applicable

      // passthroughs / overrides
      thread_id: prep.thread_id || '',
      subject: prep.subject || '',
      company: prep.company || '',
      last_internal_index: lastInternalIdx,
      last_client_index: lastClientIdx,
    }
  }
];

