parameters.jsCode:
// Follow-Up Template (test mode)
// Mode: Run Once per Item

// ---------- CONFIG ----------
const TEST_MODE = true; // set false when going live
const TEST_RECIPIENT = "pj@scalevirtually.com";

// ---------- INPUTS ----------
const threadId = $json.thread_id || null;
const company = $json.company || null;
const followupCount = Number($json.followup_count || 0);

// ---------- SUBJECT ----------
const subject = "Following up on your VA candidates";

// ---------- BODY (light professional tone) ----------
const body = `Good day,

Hope you’re doing well!

Just checking in to see if you’ve had a chance to review the candidates we sent. We’d appreciate your feedback and your availability so we can move forward with scheduling the interviews.

Looking forward to your response!

Best Regards,
Placements Team`;

// ---------- RECIPIENT ----------
let sendTo;
if (TEST_MODE) {
  sendTo = TEST_RECIPIENT; // test route
} else {
  // production route – pick most recent external sender
  sendTo =
    $json.transcript?.[$json.last_client_index]?.from_email ||
    $json.participants_external?.[0] ||
    "";
}

// ---------- OUTPUT ----------
return [
  {
    json: {
      subject,
      body,
      send_to: sendTo,
      followup_count: followupCount + 1,
      thread_id: threadId,
      template_variant: "generic",
      company,
      test_mode: TEST_MODE,
    },
  },
];

// MIME Builder for Gmail API
// Mode: Run Once per Item

// ---------- INPUTS ----------
const to = $json.send_to;                     // recipient from Follow-Up Template
const subject = $json.subject || "(no subject)";
const body = $json.body || "";
const threadId = $json.thread_id || null;
const ccList = Array.isArray($json.participants_internal)
  ? $json.participants_internal.join(", ")
  : "";

// ---------- BUILD PLAIN-TEXT MIME ----------
let mime = `To: ${to}\n`;
if (ccList) mime += `Cc: ${ccList}\n`;
mime += `Subject: ${subject}\n`;
mime += `Content-Type: text/plain; charset="UTF-8"\n\n${body}`;

// ---------- BASE64URL ENCODE ----------
const mime_b64url = Buffer.from(mime)
  .toString("base64")
  .replace(/\+/g, "-")
  .replace(/\//g, "_")
  .replace(/=+$/, "");

// ---------- OUTPUT ----------
return [
  {
    json: {
      thread_id: threadId,
      mime_b64url,
      to,
      subject,
    },
  },
];

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  item.json.myNewField = 1;
}

return $input.all();

// Update Session Log (Mode: Run Once for All Items)

// exact name of the node that has thread_id/label/... fields
const SOURCE_NODE = 'Parser + Guardrail'; // <-- change if your node name differs

const now = Date.now();
const slackItems = $input.all();              // items arriving from Slack HTTP node
const baseItems  = $items(SOURCE_NODE, 0);    // parallel items from the source node

const data = $getWorkflowStaticData('global');
data.session_log = data.session_log ?? [];

const out = slackItems.map((curr, idx) => {
  const base = baseItems[idx]?.json ?? {};  // safe lookup; may be {}
  const slack = curr.json ?? {};

  const log = {
    // from source node (may be undefined if the name/index is wrong)
    thread_id: base.thread_id,
    label: base.label,
    confidence: base.confidence,
    action: base.action,
    reason: base.reason,
    followup_count: base.followup_count ?? 0,
    last_internal_index: base.last_internal_index ?? null,
    last_client_index: base.last_client_index ?? null,

    // from Slack HTTP response
    slack_channel: slack.channel,
    slack_ts: slack.ts,
    slack_ok: slack.ok,

    decided_at_epoch: now,
  };

  data.session_log.push(log);
  return { json: log };
});

// (optional) cap log size
const MAX = 1000;
if (data.session_log.length > MAX) data.session_log = data.session_log.slice(-MAX);

return out;

// ============= LLM Prep (Gmail Thread -> compact prep) =============
// Mode: Run Once for All Items
// Input: items[0].json.{ id, historyId, messages: [ ... ] }  (Gmail "Get a thread"/Trigger format)
// Output: [ { prep: {...} } ]  OR [ { prep: { error: "..." } } ]

const INTERNAL_DOMAINS = ['scalevirtually.com'];   // adjust as needed
const SUPPRESS_ON_ANY_INTERNAL_OR_EXTERNAL_REPLY = false; // set true if any reply should stop follow-ups

function parseAddressList(raw) {
  if (!raw) return [];
  // Split on commas that separate addresses (simple but works for common cases)
  return raw
    .split(',')
    .map(s => s.trim())
    .filter(Boolean)
    .map(addr => {
      // Formats: "Name <email@x.com>" OR "email@x.com"
      const m = addr.match(/^(.*)<([^>]+)>$/);
      const email = (m ? m[2] : addr).trim();
      const name = (m ? m[1] : '').trim().replace(/^"|"$/g, '');
      const domain = (email.split('@')[1] || '').toLowerCase();
      const isInternal = INTERNAL_DOMAINS.includes(domain);
      return { email: email.toLowerCase(), name, domain, isInternal };
    });
}

function uniqBy(arr, keyFn) {
  const seen = new Set();
  const out = [];
  for (const x of arr) {
    const k = keyFn(x);
    if (!seen.has(k)) { seen.add(k); out.push(x); }
  }
  return out;
}

function header(msg, name) {
  return msg[name] || (msg.payload?.headers?.find(h => h.name === name)?.value) || undefined;
}

function firstNonEmpty(...vals) {
  return vals.find(v => v !== undefined && v !== null && v !== '');
}

function getBodySnippet(msg) {
  // Prefer Gmail 'snippet' (already compact), with a short fallback to payload text if ever needed
  if (msg.snippet) return msg.snippet;
  const body = msg.payload?.body?.data || '';
  if (!body) return '';
  try {
    const text = Buffer.from(body, 'base64').toString('utf8');
    return text.slice(0, 240);
  } catch {
    return '';
  }
}

function normalizeDate(v) {
  // returns ms timestamp (number) or null
  if (!v) return null;
  // Gmail 'internalDate' is ms as string; 'Date' is RFC2822
  if (/^\d+$/.test(String(v))) return Number(v);
  const t = Date.parse(v);
  return Number.isFinite(t) ? t : null;
}

function buildPrepFromThread(thread) {
  if (!thread || !Array.isArray(thread.messages) || !thread.messages.length) {
    return { error: 'Missing Gmail thread' };
  }

  // Sort messages by internalDate ascending
  const messages = [...thread.messages].sort((a,b) =>
    normalizeDate(a.internalDate) - normalizeDate(b.internalDate)
  );

  const threadId = firstNonEmpty(thread.id, messages[0]?.threadId);
  const subject = firstNonEmpty(header(messages[0], 'Subject'), messages[0]?.Subject) || '';
  const startedAt = normalizeDate(firstNonEmpty(messages[0]?.internalDate, header(messages[0],'Date')));
  const lastMsg = messages[messages.length - 1];
  const lastAt = normalizeDate(firstNonEmpty(lastMsg?.internalDate, header(lastMsg,'Date')));

  // Collect participants across the thread
  let allPeople = [];
  for (const m of messages) {
    allPeople = allPeople.concat(parseAddressList(header(m, 'From')));
    allPeople = allPeople.concat(parseAddressList(header(m, 'To')));
    allPeople = allPeople.concat(parseAddressList(header(m, 'Cc')));
  }
  allPeople = uniqBy(allPeople, p => p.email);

  // Original message participants (who to consider for follow-ups)
  const orig = messages[0];
  const origFrom = parseAddressList(header(orig, 'From'))[0] || null;
  const origTo = parseAddressList(header(orig, 'To'));
  const origCc = parseAddressList(header(orig, 'Cc'));
  const origRecipients = uniqBy([...origTo, ...origCc], p => p.email);

  // Replies (any message after the first where sender matches recipient)
  // Also compute whether internal/external replied
  const repliesByEmail = new Map();
  let anyReply = false;
  let anyExternalReply = false;
  let anyInternalReply = false;

  for (let i = 1; i < messages.length; i++) {
    const m = messages[i];
    const from = parseAddressList(header(m, 'From'))[0];
    if (!from) continue;
    anyReply = true;
    if (from.isInternal) anyInternalReply = true; else anyExternalReply = true;

    const ts = normalizeDate(firstNonEmpty(m.internalDate, header(m,'Date')));
    const prev = repliesByEmail.get(from.email);
    if (!prev || ts > prev) repliesByEmail.set(from.email, ts);
  }

  // Mark which original recipients replied
  const recipients = origRecipients.map(r => {
    const repliedAt = repliesByEmail.get(r.email) || null;
    return { ...r, replied: Boolean(repliedAt), repliedAt };
  });

  // External-only recipients for follow-up targeting
  const externalRecipients = recipients.filter(r => !r.isInternal);

  // Compute non-repliers (respect the global suppression flag if you want)
  const nonRepliers = externalRecipients.filter(r => {
    if (SUPPRESS_ON_ANY_INTERNAL_OR_EXTERNAL_REPLY && anyReply) return false;
    return !r.replied;
  });

  // A compact prompt seed for your LLM (token friendly)
  const lastSnippet = getBodySnippet(lastMsg);
  const latestHumanFrom = parseAddressList(header(lastMsg, 'From'))[0] || null;

  const compactHistory = messages.slice(-6).map(m => {
    const from = parseAddressList(header(m,'From'))[0];
    return {
      at: normalizeDate(firstNonEmpty(m.internalDate, header(m,'Date'))),
      from: from?.email || null,
      internal: from?.isInternal ?? null,
      snippet: getBodySnippet(m),
    };
  });

  return {
    threadId,
    subject,
    startedAt,
    lastAt,
    origin: {
      from: origFrom,
      to: origTo,
      cc: origCc,
    },
    participants: allPeople,
    recipients,                // original recipients with replied flags
    externalRecipients,        // original external recipients
    nonRepliers,               // external, no reply yet
    anyReply,
    anyExternalReply,
    anyInternalReply,
    // Minimal, LLM-friendly seed (you can feed only this to your model)
    llmSeed: {
      title: subject,
      latestFrom: latestHumanFrom,
      latestAt: lastAt,
      latestSnippet: lastSnippet,
      audience: nonRepliers.map(r => r.email),
      compactHistory,          // last few turns, trimmed to snippets/dates
    },
  };
}

// ===== main =====
const items = $input.all();
const thread = items?.[0]?.json ?? null;
const prep = buildPrepFromThread(thread);

return [{ prep }];

