parameters.jsCode:
/**
 * Draft Normalizer (LLM -> send-ready + decision flags)
 * Mode: Run Once for All Items
 *
 * Inputs expected on items[0].json:
 *  - output : string  (LLM response; may be wrapped in ```json fences)
 *  - prep   : object  (from your LLM Prep node; includes nonRepliers, subject, anyReply flags, threadId)
 *  - config : object? (optional policy toggles, see defaults below)
 *  - state  : object? (optional counters: { followUpCount, limit })
 *
 * Output (single item):
 *  {
 *    threadId, subject, to[], cc[], body,
 *    flags: { hasAudience, suppressed, hasError, readyToSend },
 *    decision: "send" | "skip_suppressed" | "limit_reached" | "no_audience" | "invalid_draft" | "needs_human",
 *    reasons: [string],
 *    _rawDraft, _prepSubject
 *  }
 */

const input = $input.first().json;

// ---------- Config (with safe defaults; override via items[0].json.config) ----------
const cfg = Object.assign({
  enforceToFromPrep: true,        // Only send to prep.nonRepliers
  allowModelTo: false,            // If true, intersect model 'to' with nonRepliers; else ignore model 'to'
  allowedCcDomains: [],           // Empty -> block all CC; else allow only these domains
  suppressOnAnyReply: true,       // If any reply happened, skip send
  requireHumanReview: false,      // Force manual review gate
  maxBodyChars: 1200,             // Hard cap on body length
  trimWhitespace: true,           // Normalize whitespace in body
}, input.config || {});

// Optional state (for limit logic)
const state = Object.assign({
  followUpCount: 0,
  limit: 2,                       // e.g., max 2 follow-ups
}, input.state || {});

// ---------- Helpers ----------
function stripCodeFence(s) {
  if (typeof s !== 'string') return '';
  return s
    .replace(/^\s*```json\s*/i, '')
    .replace(/^\s*```\s*/i, '')
    .replace(/\s*```\s*$/i, '')
    .trim();
}
function safeEmails(arr) {
  return (Array.isArray(arr) ? arr : []).filter(v => typeof v === 'string' && v.includes('@'));
}
function dedupe(arr) { return [...new Set(arr)]; }
function emailDomain(e) { return String(e).split('@')[1]?.toLowerCase() || ''; }
function filterAllowedCc(cc, domains) {
  if (!domains || !domains.length) return [];
  const set = new Set(domains.map(d => String(d).toLowerCase()));
  return cc.filter(e => set.has(emailDomain(e)));
}
function tidyBody(text) {
  let t = String(text || '');
  if (cfg.trimWhitespace) {
    t = t.replace(/[ \t]+\n/g, '\n').replace(/\n{3,}/g, '\n\n').trim();
  }
  if (t.length > cfg.maxBodyChars) t = t.slice(0, cfg.maxBodyChars) + '…';
  return t;
}

// ---------- Parse LLM JSON ----------
const raw = input.output;
const prep = input.prep || {};
const jsonStr = stripCodeFence(raw);

let draft;
try {
  draft = JSON.parse(jsonStr);
} catch (e) {
  // Try a lenient fallback: extract first {...} block
  const m = String(jsonStr).match(/\{[\s\S]*\}$/);
  if (m) {
    try { draft = JSON.parse(m[0]); }
    catch (e2) {
      return [{
        json: {
          error: 'Failed to parse LLM JSON',
          details: String(e2),
          raw: String(raw).slice(0, 500),
          decision: 'invalid_draft',
          reasons: ['json_parse_failed'],
          flags: { hasAudience: false, suppressed: false, hasError: true, readyToSend: false },
        }
      }];
    }
  } else {
    return [{
      json: {
        error: 'Failed to parse LLM JSON',
        details: String(e),
        raw: String(raw).slice(0, 500),
        decision: 'invalid_draft',
        reasons: ['json_parse_failed'],
        flags: { hasAudience: false, suppressed: false, hasError: true, readyToSend: false },
      }
    }];
  }
}

// ---------- Subject ----------
let subject = (draft.subject || '').trim();
if (!subject) subject = `Re: ${prep.subject || ''}`.trim();

// ---------- Recipients ----------
const allowedTo = new Set((prep.nonRepliers || []).map(r => r.email));
let to = safeEmails(draft.to);

if (cfg.enforceToFromPrep) {
  if (cfg.allowModelTo) {
    // Intersect model 'to' with allowed non-repliers
    to = to.filter(x => allowedTo.has(x));
    if (to.length === 0) to = Array.from(allowedTo); // if model gave none/invalid, fallback to all non-repliers
  } else {
    // Ignore model 'to'; use all non-repliers
    to = Array.from(allowedTo);
  }
}
to = dedupe(to);

// CC (default: block all unless domains are whitelisted)
let cc = safeEmails(draft.cc || []);
cc = filterAllowedCc(cc, cfg.allowedCcDomains);
cc = dedupe(cc);

// ---------- Body ----------
let body = tidyBody(draft.body || '');
const bodyMissing = body.length === 0;

// ---------- Policy checks / decisions ----------
const suppressed = Boolean(cfg.suppressOnAnyReply && (prep.anyExternalReply || prep.anyReply));
const overLimit = Number(state.followUpCount || 0) >= Number(state.limit || 0);
const hasAudience = Array.isArray(to) && to.length > 0;
const hasError = Boolean(draft.error) || bodyMissing;

let decision = 'send';
const reasons = [];
if (hasError) { decision = 'invalid_draft'; reasons.push(bodyMissing ? 'body_missing' : 'draft_error_flag'); }
if (suppressed) { decision = 'skip_suppressed'; reasons.push('meaningful_reply_detected'); }
if (overLimit) { decision = 'limit_reached'; reasons.push('followup_limit_reached'); }
if (!hasAudience) { decision = (decision === 'send') ? 'no_audience' : decision; reasons.push('no_nonrepliers'); }
if (cfg.requireHumanReview === true) { decision = 'needs_human'; reasons.push('manual_approval_required'); }

// Ready flag mirrors decision
const readyToSend = (decision === 'send');

// ---------- Output ----------
return [{
  json: {
    threadId: prep.threadId,
    subject,
    to,
    cc,
    body,
    flags: {
      hasAudience,
      suppressed,
      hasError,
      readyToSend
    },
    decision,   // <- drive IF/Switch on this
    reasons,    // <- useful for Airtable/Slack logs
    // for observability
    _rawDraft: draft,
    _prepSubject: prep.subject
  }
}];

// Extract LLM text into { output: "<string>" } and pass through prep if present
const j = $input.first().json;

function firstText(x) {
  if (!x) return '';
  if (typeof x === 'string') return x;

  // Common shapes
  if (typeof x.output === 'string') return x.output;
  if (typeof x.result === 'string') return x.result;
  if (typeof x.text === 'string') return x.text;
  if (typeof x.response === 'string') return x.response;

  // OpenAI-style
  const oai = x.choices?.[0]?.message?.content;
  if (typeof oai === 'string') return oai;

  // Gemini-style (n8n / REST)
  const gemParts = x.response?.candidates?.[0]?.content?.parts
                ?? x.candidates?.[0]?.content?.parts;
  if (Array.isArray(gemParts)) {
    const txt = gemParts.map(p => p.text).filter(Boolean).join('\n').trim();
    if (txt) return txt;
  }

  // Last resort: stringify
  try { return JSON.stringify(x); } catch { return ''; }
}

return [{
  json: {
    ...j,
    output: firstText(j)
  }
}];

